<template><div class="panel"><div class="section-head"><div><h2>{{ t('providers.title') }}</h2><p>{{ t('providers.description') }}</p></div><el-button v-if="auth.hasPermission('model:provider:create')" type="primary" @click="open()">{{ t('providers.add') }}</el-button></div><el-table :data="rows"><el-table-column prop="code" :label="t('common.code')"/><el-table-column prop="name" :label="t('common.name')"/><el-table-column prop="baseUrl" :label="t('providers.baseUrl')"/><el-table-column prop="concurrencyLevel" :label="t('providers.concurrencyLevel')"/><el-table-column prop="concurrencyLimit" :label="t('providers.concurrency')"/><el-table-column :label="t('common.operation')"><template #default="s"><el-button v-if="auth.hasPermission('model:provider:update')" link type="primary" @click="viewKeys(s.row)">{{ t('providers.viewKeys') }}</el-button><el-button v-if="auth.hasPermission('model:provider:update')" link type="primary" @click="open(s.row)">{{ t('common.edit') }}</el-button><el-button link type="danger" @click="remove(s.row)">{{ t('common.delete') }}</el-button></template></el-table-column></el-table><el-dialog v-model="visible" :title="form.id?t('providers.edit'):t('providers.add')" width="620px"><el-form label-width="100px"><el-form-item :label="t('common.code')"><el-input v-model="form.code"/></el-form-item><el-form-item :label="t('common.name')"><el-input v-model="form.name"/></el-form-item><el-form-item label="Base URL"><el-input v-model="form.baseUrl"/></el-form-item><el-form-item :label="t('providers.apiKeys')"><el-input v-model="form.apiKeys" type="textarea" :rows="5" :placeholder="t('providers.multipleKeys')"/></el-form-item><el-form-item :label="t('providers.concurrencyLevel')"><el-select v-model="form.concurrencyLevel"><el-option :label="t('providers.provider')" value="PROVIDER"/><el-option label="API Key" value="API_KEY"/></el-select></el-form-item><el-form-item :label="t('providers.concurrency')"><el-input-number v-model="form.concurrencyLimit" :min="1"/></el-form-item><el-form-item :label="t('providers.timeout')"><el-input-number v-model="form.timeoutSeconds" :min="1"/></el-form-item><el-form-item :label="t('common.enabled')"><el-switch v-model="form.enabled"/></el-form-item></el-form><template #footer><el-button @click="visible=false">{{ t('common.cancel') }}</el-button><el-button type="primary" @click="save">{{ t('common.save') }}</el-button></template></el-dialog><el-dialog v-model="keysVisible" :title="t('providers.viewKeys')" width="520px"><el-input v-model="keysContent" type="textarea" :rows="5" readonly/></el-dialog></div></template>
<script setup>import{onMounted,reactive,ref}from'vue';import{ElMessage,ElMessageBox}from'element-plus';import{useI18n}from'vue-i18n';import http from'../api/http';import{useAuthStore}from'../stores/auth';import{normalizeApiKeys}from'../utils/apiKeys';const{t}=useI18n();const auth=useAuthStore(),rows=ref([]),visible=ref(false),keysVisible=ref(false),keysContent=ref(''),form=reactive({id:null,code:'',name:'',baseUrl:'',apiKeys:'',concurrencyLimit:4,concurrencyLevel:'PROVIDER',timeoutSeconds:60,enabled:true});async function load(){rows.value=(await http.get('/models/providers')).data}/** 获取并规范化指定供应商的明文 API Key。 */async function loadKeys(id){return normalizeApiKeys((await http.get(`/models/providers/${id}/api-keys`)).data.apiKeys)}/** 打开供应商窗口，编辑时回显全部 API Key。 */async function open(row){Object.assign(form,row?{...row,apiKeys:await loadKeys(row.id)}:{id:null,code:'',name:'',baseUrl:'',apiKeys:'',concurrencyLimit:4,concurrencyLevel:'PROVIDER',timeoutSeconds:60,enabled:true});visible.value=true}/** 查看供应商的明文 API Key。 */async function viewKeys(row){keysContent.value=await loadKeys(row.id);keysVisible.value=true}/** 保存供应商。 */async function save(){form.apiKeys=normalizeApiKeys(form.apiKeys);form.id?await http.put(`/models/providers/${form.id}`,form):await http.post('/models/providers',form);visible.value=false;await load();ElMessage.success(t('common.successSaved'))}/** 删除供应商。 */async function remove(row){await ElMessageBox.confirm(t('common.confirmDelete',{name:row.name}),t('common.deleteConfirm'),{type:'warning'});await http.delete(`/models/providers/${row.id}`);await load();ElMessage.success(t('common.successDeleted'))}onMounted(load)</script>
